790→  <!-- Anonymous Contact Form Submission -->
791→  <script>
792→    function submitContactForm(event) {
793→      event.preventDefault();
794→      var messageEl = document.getElementById('contact-message');
795→      var nameEl = document.getElementById('contact-name');
796→      var emailEl = document.getElementById('contact-email');
797→      var urlEl = document.getElementById('contact-url');
798→      var categoryEl = document.getElementById('contact-category');
799→      var statusEl = document.getElementById('form-status');
800→      var message = messageEl.value.trim();
801→
802→      if (!message) return;
803→
804→      statusEl.textContent = 'Sending...';
805→      statusEl.className = 'mt-3 text-sm text-gray-400';
806→
807→      var webhookUrl = 'https://n8n.cloudpublica.org/webhook/justnice-contact';
808→
809→      fetch(webhookUrl, {
810→        method: 'POST',
811→        headers: { 'Content-Type': 'application/json' },
812→        body: JSON.stringify({
813→          message: message,
814→          name: nameEl.value.trim(),
815→          email: emailEl.value.trim(),
816→          url: urlEl.value.trim(),
817→          category: categoryEl.value,
818→          source: 'justnice.us/blog/rebuilding-resilience',
819→          page: window.location.pathname,
820→          timestamp: new Date().toISOString()
821→        })
822→      })
823→      .then(function (response) {
824→        if (response.ok) {
825→          statusEl.textContent = 'Thank you! Your message has been sent.';
826→          statusEl.className = 'mt-3 text-sm text-green-400';
827→          messageEl.value = '';
828→          nameEl.value = '';
829→          emailEl.value = '';
830→          urlEl.value = '';
831→          categoryEl.value = '';
832→        } else {
833→          throw new Error('Network response was not ok');
834→        }
835→      })
836→      .catch(function () {
837→        statusEl.textContent = 'Something went wrong. Please try again.';
838→        statusEl.className = 'mt-3 text-sm text-red-400';
839→      });
840→    }
841→  </script>
